mapper.select:
SELECT * FROM ( SELECT r.review_id AS reviewId, r.user_account_id AS authorAccountId, d.nickname, d.handle, d.role_type AS roleType, d.profile_image_url AS profileImageUrl, r.status, TO_CHAR(r.created_at, 'YYYY-MM-DD HH24:MI:SS') AS createdAt, r.content AS content, ROW_NUMBER() OVER( ORDER BY
r.created_at ASC r.created_at DESC
) AS rn FROM trainers_reviews r JOIN vw_account_display d ON r.user_account_id = d.account_id
) WHERE rn > ( (#{page} - 1) * #{size} ) AND rn <= ( #{page} * #{size} )

mapper.update:
UPDATE trainers_reviews
SET status = 'HIDDEN'
WHERE review_id = #{reviewId}
